            elif numbers[l] + numbers[r] < target:
                l += 1
            else:
                r -= 1

expression-add-operators.solution:
class Solution(object):
    def addOperators(self, num, target):
        """
        :type num: str
        :type target: int
        :rtype: List[str]
        """
        def backtrack(index, current, result, total):
            if index == len(num):
                if total == target:
                    result.append(current)
                return
            # Add a digit
            backtrack(index + 1, current + num[index], result, total + int(num[index]))
            # Add a plus sign
            if current and current[-1] != '0':
                backtrack(index + 1, current + '+' + num[index], result, total)
            # Add a minus sign
            if current and current[-1] != '0':
                backtrack(index + 1, current + '-' + num[index], result, total)
            # Add a multiplication sign
            if current and current[-1] != '0':
                backtrack(index + 1, current + '*' + num[index], result, total - current[-1] + current[-1] * int(num[index]))

        result = []
        backtrack(0, '', result, 0)
        return result

