class Solution(object):
    def smallestDistancePair(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        nums.sort()
        l, r = 0, nums[-1] - nums[0]

        while l < r:
            mid = (l + r) // 2
            count = 0

            for i in range(len(nums) - 1):
                j = bisect.bisect_left(nums, nums[i] + mid + 1)
                count += j - (i + 1)

            if count < k:
                l = mid + 1
            else:
                r = mid

        return l

