contains-duplicate-iii.solution:
class Solution(object):
    def containsNearbyAlmostDuplicate(self, nums, indexDiff, valueDiff):
        """
        :type nums: List[int]
        :type indexDiff: int
        :type valueDiff: int
        :rtype: bool
        """
        # Use a dictionary to store the values and their indices
        value_indices = {}

        for i, num in enumerate(nums):
            # Check if the current number is within the range of the last indexDiff elements
            for j in range(max(0, i - indexDiff), i):
                # If the difference between the current number and the number at index j is within the valueDiff range
                if abs(num - nums[j]) <= valueDiff:
                    return True

            # Add the current number and its index to the dictionary
            value_indices[num] = i

        # If no such pair is found, return False
        return False

