class Solution(object):
    def addStrings(self, num1, num2):
        """
        :type num1: str
        :type num2: str
        :rtype: str
        """
        res = []
        i, j, carry = len(num1) - 1, len(num2) - 1, 0
        while i >= 0 or j >= 0 or carry:
            if i >= 0:
                carry += ord(num1[i]) - ord('0')
                i -= 1
            if j >= 0:
                carry += ord(num2[j]) - ord('0')
                j -= 1
            res.append(str(carry % 10))
            carry //= 10
        return ''.join(res[::-1])

basic-calculator.solution:
class Solution(object):
    def calculate(self, s):
        """
        :type s: str
        :rtype: int
        """
        stack = []
        num = 0
        sign = '+'
        for c in s + '+':
            if c.isdigit():
                num = num * 10 + int(c)
            elif c in '+-':
                self.push(stack, num, sign)
                num = 0
                sign = c
            elif c == '(':
                stack.append(sign)
                stack.append(num)
                num = 0
                sign = '+'
            elif c == ')':
                self.push(stack, num, sign)
                num = 0
                sign = stack.pop()
                num = stack.pop()
        return sum(stack)

    def push(self, stack, num, sign):
        if sign == '+':
            stack.append(num)
        elif sign == '-':
            stack.append(-num)
        elif sign == '*':
            stack.append(stack.pop() * num)
        elif sign == '/':
            stack.append(int(stack.pop() / num))

valid-parentheses.solution:
class Solution(object):
    def isValid(self, s):
        """
        :type s: str
        :rtype: bool
        """
        stack = []
        mapping = {")": "(", "}": "{", "]": "["}

        for char in s:
            if char in mapping.values():
                stack.append(char)
            elif char in mapping.keys():
                if not stack or mapping[char] != stack.pop():
                    return False
        return not stack

