class Solution(object):
    def arrangeCoins(self, n):
        """
        :type n: int
        :rtype: int
        """
        # Using binary search to find the number of complete rows
        left, right = 1, n
        while left <= right:
            mid = (left + right) // 2
            if mid * (mid + 1) // 2 <= n:
                left = mid + 1
            else:
                right = mid - 1
        return right

