swim-in-rising-water.solution:
from heapq import heappush, heappop
class Solution(object):
    def swimInWater(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        n = len(grid)
        directions = [(0, 1), (1, 0), (-1, 0), (0, -1)]
        visited = set()
        heap = [(grid[0][0], 0, 0)]
        while heap:
            time, x, y = heappop(heap)
            if (x, y) == (n - 1, n - 1):
                return time
            visited.add((x, y))
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < n and 0 <= ny < n and (nx, ny) not in visited:
                    heappush(heap, (max(time, grid[nx][ny]), nx, ny))

unique-paths.solution:
class Solution(object):
    def uniquePaths(self, m, n):
        """
        :type m: int
        :type n: int
        :rtype: int
        """
        if m == 1 or n == 1:
            return 1
        dp = [[0] * n for _ in range(m)]
        for i in range(m):
            dp[i][0] = 1
        for j in range(n):
            dp[0][j] = 1
        for i in range(1, m):
            for j in range(1, n):
                dp[i][j] = dp[i-1][j] + dp[i][j-1]
        return dp[m-1][n-1]

