class Solution(object):
    def removeInvalidParentheses(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        def isValid(s):
            balance = 0
            for c in s:
                if c == '(':
                    balance += 1
                elif c == ')':
                    balance -= 1
                if balance < 0:
                    return False
            return balance == 0

        def dfs(s, path, res):
            if not s:
                if isValid(path):
                    res.append(path)
                return
            for i in range(len(s)):
                if i == 0 or s[i] != s[i-1]:
