from collections import deque
class Solution(object):
    def trapRainWater(self, heightMap):
        """
        :type heightMap: List[List[int]]
        :rtype: int
        """
        if not heightMap or not heightMap[0]:
            return 0

        rows, cols = len(heightMap), len(heightMap[0])
        visited = [[False] * cols for _ in range(rows)]
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
        queue = deque()

        # Add all cells with height 0 to the queue
        for i in range(rows):
            for j in range(cols):
                if heightMap[i][j] == 0:
                    queue.append((i, j))
                    visited[i][j] = True

        # Perform BFS to find all cells with height 0
        while queue:
            x, y = queue.popleft()
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < rows and 0 <= ny < cols and not visited[nx][ny]:
                    visited[nx][ny] = True
                    queue.append((nx, ny))
                    heightMap[nx][ny] = max(heightMap[nx][ny], heightMap[x][y])

        # Calculate the volume of water trapped
        volume = 0
        for i in range(rows):
            for j in range(cols):
                if heightMap[i][j] > 0:
                    volume += max(0, heightMap[i][j] - heightMap[i][j-1])
                    volume += max(0, heightMap[i][j] - heightMap[i-1][j])

        return volume

