                return abs(cards[0] - 24) < 1e-6
            for i in range(len(cards)):
                for j in range(i + 1, len(cards)):
                    for op in ['+', '-', '*', '/']:
                        if op == '/':
                            if cards[j] == 0:
                                continue
                        new_cards = [cards[k] for k in range(len(cards)) if k != i and k != j]
