class Solution(object):
    def kInversePairs(self, n, k):
        """
        :type n: int
        :type k: int
        :rtype: int
        """
        MOD = 10**9 + 7
        dp = [[0] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 1

        for i in range(1, n + 1):
            for j in range(k + 1):
                for x in range(max(0, j - i + 1), j + 1):
                    dp[i][j] = (dp[i][j] + dp[i - 1][x]) % MOD

        return dp[n][k]

