        def check(mid):
            cnt = 1
            total = 0
            for num in nums:
                total += num
                if total > mid:
                    cnt += 1
                    total = num
            return cnt <= k

        left, right = max(nums), sum(nums)
        while left < right:
            mid = (left + right) // 2
            if check(mid):
                right = mid
            else:
                left = mid + 1
        return left

