        left, right = 0, len(nums) - 1

        while left <= right:
            mid = (left + right) // 2

            if nums[mid] == target:
                return mid

            if nums[left] <= nums[mid]:
                if nums[left] <= target < nums[mid]:
                    right = mid - 1
                else:
                    left = mid + 1
            else:
                if nums[mid] < target <= nums[right]:
                    left = mid + 1
                else:
                    right = mid - 1

        return -1

find-the-closest-palindrome.solution:
class Solution(object):
    def nearestPalindromic(self, n):
        """
        :type n: str
        :rtype: str
        """
        # If the length of the number is 1, return the number minus 1
        if len(n) == 1:
            return str(int(n) - 1)

        # If the number is already a palindrome, return the next smallest palindrome
        if n == n[::-1]:
            # Find the next smallest palindrome by incrementing the last digit
            next_palindrome = int(n) + 1
            while not str(next_palindrome) == str(next_palindrome)[::-1]:
                next_palindrome += 1
            return str(next_palindrome)

        # If the number is not a palindrome, find the next smallest palindrome
        # by finding the closest palindrome to the original number
        closest_palindrome = int(n)
        for i in range(1, len(n)):
            # Find the closest palindrome to the original number by incrementing the last digit
            next_palindrome = int(n[:i]) + 1
            while not str(next_palindrome) == str(next_palindrome)[::-1]:
                next_palindrome += 1
            # Check if the difference between the original number and the next palindrome is smaller than the difference between the original number and the closest palindrome
            if abs(int(n) - next_palindrome) < abs(int(n) - closest_palindrome):
                closest_palindrome = next_palindrome
        return str(closest_palindrome)

