class Solution(object):
    def numDecodings(self, s):
        """
        :type s: str
        :rtype: int
        """
        MOD = 10**9 + 7
        n = len(s)
        dp = [0] * (n + 1)
        dp[0] = 1

        if s[0] == '0':
            return 0

        for i in range(1, n + 1):
            if s[i - 1] == '*':
                if i == 1:
                    dp[i] = 9
                else:
                    dp[i] = (dp[i - 1] * 9) % MOD
                    if s[i - 2] == '1':
                        dp[i] = (dp[i] + (dp[i - 2] * 9) % MOD) % MOD
                    elif s[i - 2] == '2':
                        dp[i] = (dp[i] + (dp[i - 2] * 6) % MOD) % MOD
                    elif s[i - 2] == '*':
                        dp[i] = (dp[i] + (dp[i - 2] * 15) % MOD) % MOD
            elif s[i - 1] == '0':
                if i == 1:
                    return 0
                else:
                    dp[i] = dp[i - 2]
            else:
                if s[i - 2] == '1':
                    dp[i] = (dp[i - 1] + dp[i - 2]) % MOD
                elif s[i - 2] == '2':
                    if s[i - 1] <= '6':
                        dp[i] = (dp[i - 1] + dp[i - 2]) % MOD
                    else:
                        dp[i] = dp[i - 1]
                elif s[i - 2] == '*':
                    if s[i - 1] <= '6':
                        dp[i] = (dp[i - 1] + (dp[i - 2] * 2)) % MOD
                    else:
                        dp[i] = (dp[i - 1] + (dp[i - 2] * 1)) % MOD

        return dp[-1]

