class Solution(object):
    def countSmaller(self, nums):
        """
        :type nums: List[int]
        :rtype: List[int]
        """
        def merge_sort(arr):
            if len(arr) <= 1:
                return arr
            mid = len(arr) // 2
            left = merge_sort(arr[:mid])
            right = merge_sort(arr[mid:])
            return merge(left, right)

        def merge(left, right):
            i = j = k = 0
            left_len, right_len = len(left), len(right)
            merged = [0] * (left_len + right_len)
            while i < left_len and j < right_len:
                if left[i] <= right[j]:
                    merged[k] = left[i]
                    i += 1
                else:
                    merged[k] = right[j]
                    j += 1
                    k += 1
            while i < left_len:
                merged[k] = left[i]
                i += 1
                k += 1
            while j < right_len:
                merged[k] = right[j]
                j += 1
                k += 1
            return merged

        sorted_nums = merge_sort(nums)
        count_map = {num: i for i, num in enumerate(sorted_nums)}
        return [count_map[num] for num in nums]

