class Solution(object):
    def countOfAtoms(self, formula):
        """
        :type formula: str
        :rtype: str
        """
        stack = []
        num = 0
        for i in range(len(formula)):
            if formula[i].isupper():
                if stack:
                    stack[-1]['name'] += formula[i]
                else:
                    stack.append({'name': formula[i]})
                num = 0
            elif formula[i].islower():
                if stack:
                    stack[-1]['name'] += formula[i]
                else:
                    stack.append({'name': formula[i]})
            elif formula[i].isdigit():
                num = num * 10 + int(formula[i])
            elif formula[i] == '(':
                stack.append({'num': num})
                num = 0
            elif formula[i] == ')':
                tmp = {}
                while stack and stack[-1]['name'] != '(':
                    tmp.update(stack.pop())
                stack.pop()
                if stack:
                    stack[-1]['num'] += tmp['num']
                else:
                    stack.append(tmp)
                num = 0
        res = {}
        for item in stack:
            if item['name'] not in res:
                res[item['name']] = item['num']
            else:
                res[item['name']] += item['num']
        res = sorted(res.items(), key=lambda x: x[0])
        return ''.join([x[0] + (str(x[1]) if x[1] > 1 else '') for x in res])

