fraction-to-recurring-decimal.solution:
class Solution(object):
    def fractionToDecimal(self, numerator, denominator):
        """
        :type numerator: int
        :type denominator: int
        :rtype: str
        """
        if numerator == 0:
            return "0"
        if denominator == 0:
            raise ValueError("Denominator cannot be zero")

        sign = "-" if (numerator < 0) ^ (denominator < 0) else ""
        numerator, denominator = abs(numerator), abs(denominator)
        integer_part = numerator // denominator
        remainder = numerator % denominator

        if remainder == 0:
            return sign + str(integer_part)

        decimal_part = []
        seen_remainders = set()

        while remainder != 0:
            if remainder in seen_remainders:
                return sign + str(integer_part) + "." + "".join(decimal_part) + "(" + "".join(decimal_part[decimal_part.index(remainder):]) + ")"
            seen_remainders.add(remainder)
            decimal_part.append(str(remainder * 10 // denominator))
            remainder = remainder * 10 % denominator

        return sign + str(integer_part) + "." + "".join(decimal_part)

