sudoku-solver.solution:
class Solution(object):
    def solveSudoku(self, board):
        """
        :type board: List[List[str]]
        :rtype: None Do not return anything, modify board in-place instead.
        """
        def is_valid(board, row, col, num):
            # Check row
            for i in range(9):
                if board[row][i] == str(num):
                    return False
            # Check column
            for i in range(9):
                if board[i][col] == str(num):
                    return False
            # Check 3x3 box
            start_row = row - row % 3
            start_col = col - col % 3
            for i in range(3):
                for j in range(3):
                    if board[start_row + i][start_col + j] == str(num):
                        return False
            return True

        def backtrack(board):
            for i in range(9):
                for j in range(9):
                    if board[i][j] == '.':
                        for num in range(1, 10):
                            if is_valid(board, i, j, num):
                                board[i][j] = str(num)
                                if backtrack(board):
                                    return True
                                board[i][j] = '.'
                        return False
            return True

        backtrack(board)

