class Solution(object):
    def isPerfectSquare(self, num):
        """
        :type num: int
        :rtype: bool
        """
        if num == 1:
            return True
        left, right = 0, num
        while left <= right:
            mid = (left + right) // 2
            if mid * mid == num:
                return True
            elif mid * mid < num:
                left = mid + 1
            else:
                right = mid - 1
        return False

scramble-string.solution:
class Solution(object):
    def isScramble(self, s1, s2):
        """
        :type s1: str
        :type s2: str
        :rtype: bool
        """
        if len(s1) != len(s2): return False
        if s1 == s2: return True
        if sorted(s1) != sorted(s2): return False

        n = len(s1)
        dp = [[False] * n for _ in range(n)]

        for i in range(n):
            for j in range(n):
                if s1[i] == s2[j]:
                    dp[i][j] = True

        for length in range(2, n + 1):
            for i in range(n - length + 1):
                for j in range(n - length + 1):
                    for k in range(1, length):
                        if (dp[i][j] and dp[i + k][j + k] and s1[i:i + k] == s2[j:j + k]) or \
                           (dp[i][j + length - k] and dp[i + k][j] and s1[i:i + k] == s2[j + length - k:j + length]):
                            dp[i][j] = True
                            break
        return dp[0][0]

