class Solution(object):
    def isValidSudoku(self, board):
        """
        :type board: List[List[str]]
        :rtype: bool
        """
        # Check rows
        for row in board:
            if len(set(row)) != len(row):
                return False

        # Check columns
        for col in range(9):
            if len(set([board[i][col] for i in range(9)])) != len([board[i][col] for i in range(9)]):
                return False

        # Check 3x3 sub-boxes
        for i in range(3):
            for j in range(3):
                sub_box = [board[x][y] for x in range(i*3, (i+1)*3) for y in range(j*3, (j+1)*3)]
                if len(set(sub_box)) != len(sub_box):
                    return False

        return True

