class Solution(object):
    def permute(self, nums):
        """
        :type nums: List[int]
        :rtype: List[List[int]]
        """
        if len(nums) == 0:
            return []
        if len(nums) == 1:
            return [nums]

        res = []
        for i in range(len(nums)):
            n = nums[i]
            rest = nums[:i] + nums[i+1:]
            for perm in self.permute(rest):
                res.append([n] + perm)
        return res

