class Solution(object):
    def searchMatrix(self, matrix, target):
        """
        :type matrix: List[List[int]]
        :type target: int
        :rtype: bool
        """
        if not matrix or not matrix[0]:
            return False
        m, n = len(matrix), len(matrix[0])
        i, j = 0, n-1
        while i < m and j >= 0:
            if matrix[i][j] == target:
                return True
            elif matrix[i][j] < target:
                i += 1
            else:
                j -= 1
        return False

text-justification.solution:
class Solution(object):
    def fullJustify(self, words, maxWidth):
        """
        :type words: List[str]
        :type maxWidth: int
        :rtype: List[str]
        """
        res = []
        cur = []
        cur_len = 0
        for w in words:
            if cur_len + len(w) > maxWidth:
                if len(cur) == 1:
                    res.append(cur[0] + ' ' * (maxWidth - cur_len))
                else:
                    spaces = maxWidth - cur_len
                    avg_spaces = spaces // (len(cur) - 1)
                    extra_spaces = spaces % (len(cur) - 1)
                    line = ''
                    for i in range(len(cur)):
                        line += cur[i]
                        if i < len(cur) - 1:
                            line += ' ' * (avg_spaces + (1 if i < extra_spaces else 0))
                    res.append(line)
                cur = [w]
                cur_len = len(w)
            else:
                cur.append(w)
                cur_len += len(w)
        if cur:
            res.append(' '.join(cur) + ' ' * (maxWidth - cur_len))
        return res

